Great question! Logging is crucial for security monitoring and incident response. However, many developers make critical mistakes with log retention that can cripple forensic investigations.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const fs = require('fs');
const app = express();

// BAD: Logging to a single file with no rotation or retention
const logFile = fs.createWriteStream('./app.log', { flags: 'a' });

function log(message) {
  const timestamp = new Date().toISOString();
  logFile.write(`${timestamp} - ${message}\n`);
}

app.use((req, res, next) => {
  log(`${req.method} ${req.url} from ${req.ip}`);
  next();
});

app.post('/api/login', (req, res) => {
  const { username, password } = req.body;
  // BAD: No security event logging
  // BAD: Password potentially logged
  log(`Login attempt for user: ${username}`);

  // Authentication logic here
  res.json({ success: true });
});

app.use((err, req, res, next) => {
  // BAD: Error details logged but may be overwritten
  log(`Error: ${err.message}`);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000);
```

**Problems with this approach**:
```text
1. Single log file grows indefinitely until disk is full
2. No log rotation - old logs overwritten or lost
3. No retention policy - logs deleted during maintenance
4. No log integrity protection - attackers can modify logs
5. No centralized storage - logs lost if server compromised
```

**Why This Is Dangerous**:
- **Forensic blindness**: When a breach is discovered months later, critical evidence is gone
- **Compliance violations**: GDPR, PCI-DSS, HIPAA require 1-7 year log retention
- **Incident timeline gaps**: Cannot determine when initial compromise occurred
- **Legal liability**: Cannot prove due diligence or breach timeline

**SECURE VERSION**:

```javascript
const express = require('express');
const winston = require('winston');
const DailyRotateFile = require('winston-daily-rotate-file');
const crypto = require('crypto');

const app = express();

// Configure log retention with rotation
const securityTransport = new DailyRotateFile({
  filename: 'logs/security-%DATE%.log',
  datePattern: 'YYYY-MM-DD',
  maxSize: '100m',
  maxFiles: '365d',  // Keep logs for 1 year minimum
  compress: true,    // Compress old logs
  auditFile: 'logs/security-audit.json'
});

const applicationTransport = new DailyRotateFile({
  filename: 'logs/application-%DATE%.log',
  datePattern: 'YYYY-MM-DD',
  maxSize: '100m',
  maxFiles: '90d',  // Application logs for 90 days
  compress: true
});

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    securityTransport,
    applicationTransport
  ]
});

// Generate log entry hash for integrity verification
function hashLogEntry(entry) {
  return crypto.createHash('sha256').update(JSON.stringify(entry)).digest('hex');
}

function securityLog(event, data) {
  const entry = {
    type: 'SECURITY',
    event: event,
    data: data,
    timestamp: new Date().toISOString()
  };
  entry.hash = hashLogEntry(entry);
  logger.warn(entry);
}

app.use((req, res, next) => {
  logger.info({
    type: 'REQUEST',
    method: req.method,
    url: req.url,
    ip: req.ip,
    userAgent: req.get('User-Agent')
  });
  next();
});

app.post('/api/login', (req, res) => {
  const { username } = req.body;
  // Never log passwords!
  securityLog('LOGIN_ATTEMPT', {
    username: username,
    ip: req.ip,
    userAgent: req.get('User-Agent')
  });

  res.json({ success: true });
});

app.listen(3000);
```

**Key Security Controls**:
- **Log rotation**: Daily rotation prevents single-file growth issues
- **Retention policy**: Security logs kept 365 days, application logs 90 days
- **Compression**: Old logs compressed to save storage
- **Integrity hashing**: Each security log entry has a hash for tamper detection
- **Structured logging**: JSON format enables automated analysis

Excellent security thinking! Centralized, immutable log storage is critical for incident response and compliance. Here's a production-ready pattern that addresses both concerns.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const DailyRotateFile = require('winston-daily-rotate-file');
const { ElasticsearchTransport } = require('winston-elasticsearch');
const { Client } = require('@elastic/elasticsearch');
const crypto = require('crypto');
const os = require('os');

const app = express();

// Environment-based configuration
const config = {
  retention: {
    security: process.env.SECURITY_LOG_RETENTION_DAYS || 365,
    audit: process.env.AUDIT_LOG_RETENTION_DAYS || 2555,  // 7 years for PCI-DSS
    application: process.env.APP_LOG_RETENTION_DAYS || 90
  },
  elasticsearch: {
    node: process.env.ELASTICSEARCH_URL || 'https://logs.internal:9200',
    auth: {
      apiKey: process.env.ELASTICSEARCH_API_KEY
    },
    tls: {
      rejectUnauthorized: process.env.NODE_ENV === 'production'
    }
  }
};

// Elasticsearch client for centralized logging
const esClient = new Client(config.elasticsearch);

// Chain hash for tamper-evident logging
let previousHash = 'GENESIS';

function createChainedHash(entry) {
  const data = JSON.stringify(entry) + previousHash;
  const newHash = crypto.createHash('sha256').update(data).digest('hex');
  previousHash = newHash;
  return newHash;
}

// Custom format for compliance logging
const complianceFormat = winston.format((info) => {
  return {
    ...info,
    hostname: os.hostname(),
    pid: process.pid,
    environment: process.env.NODE_ENV,
    applicationId: process.env.APP_ID || 'unknown',
    chainHash: createChainedHash(info)
  };
});

// Local file transport with retention
const localSecurityTransport = new DailyRotateFile({
  filename: '/var/log/app/security-%DATE%.log',
  datePattern: 'YYYY-MM-DD',
  maxSize: '500m',
  maxFiles: `${config.retention.security}d`,
  compress: true,
  auditFile: '/var/log/app/security-audit.json',
  createSymlink: true,
  symlinkName: 'security-current.log'
});

// Elasticsearch transport for centralized, immutable storage
const esTransport = new ElasticsearchTransport({
  level: 'info',
  client: esClient,
  indexPrefix: 'security-logs',
  indexSuffixPattern: 'YYYY-MM',
  ensureIndexTemplate: true,
  indexTemplate: {
    settings: {
      number_of_shards: 2,
      number_of_replicas: 1,
      'index.lifecycle.name': 'security-log-retention',
      'index.lifecycle.rollover_alias': 'security-logs'
    }
  },
  transformer: (logData) => {
    return {
      '@timestamp': logData.timestamp || new Date().toISOString(),
      severity: logData.level,
      message: logData.message,
      fields: logData
    };
  }
});

// Main logger configuration
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
    complianceFormat(),
    winston.format.json()
  ),
  transports: [
    localSecurityTransport,
    esTransport
  ],
  exceptionHandlers: [
    new winston.transports.File({ filename: '/var/log/app/exceptions.log' })
  ],
  rejectionHandlers: [
    new winston.transports.File({ filename: '/var/log/app/rejections.log' })
  ]
});

// Audit logger for compliance-critical events (7-year retention)
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    complianceFormat(),
    winston.format.json()
  ),
  transports: [
    new DailyRotateFile({
      filename: '/var/log/app/audit-%DATE%.log',
      datePattern: 'YYYY-MM',
      maxFiles: `${config.retention.audit}d`,
      compress: true
    }),
    new ElasticsearchTransport({
      level: 'info',
      client: esClient,
      indexPrefix: 'audit-logs',
      indexSuffixPattern: 'YYYY-MM'
    })
  ]
});

// Security event categories for compliance mapping
const SecurityEvents = {
  AUTHENTICATION: {
    LOGIN_SUCCESS: 'AUTH_LOGIN_SUCCESS',
    LOGIN_FAILURE: 'AUTH_LOGIN_FAILURE',
    LOGOUT: 'AUTH_LOGOUT',
    MFA_SUCCESS: 'AUTH_MFA_SUCCESS',
    MFA_FAILURE: 'AUTH_MFA_FAILURE',
    PASSWORD_CHANGE: 'AUTH_PASSWORD_CHANGE',
    ACCOUNT_LOCKED: 'AUTH_ACCOUNT_LOCKED'
  },
  AUTHORIZATION: {
    ACCESS_GRANTED: 'AUTHZ_ACCESS_GRANTED',
    ACCESS_DENIED: 'AUTHZ_ACCESS_DENIED',
    PRIVILEGE_ESCALATION: 'AUTHZ_PRIVILEGE_ESCALATION'
  },
  DATA_ACCESS: {
    READ: 'DATA_READ',
    CREATE: 'DATA_CREATE',
    UPDATE: 'DATA_UPDATE',
    DELETE: 'DATA_DELETE',
    EXPORT: 'DATA_EXPORT'
  }
};

// Compliance-aware security logging function
function logSecurityEvent(eventType, details, req = null) {
  const entry = {
    eventType: eventType,
    category: eventType.split('_')[0],
    timestamp: new Date().toISOString(),
    details: {
      ...details,
      // Never log sensitive data
      password: undefined,
      token: undefined,
      apiKey: undefined
    },
    source: {
      ip: req?.ip || 'system',
      userAgent: req?.get('User-Agent') || 'system',
      sessionId: req?.sessionID || null
    },
    compliance: {
      pciDss: ['10.2.1', '10.2.2', '10.2.4', '10.2.5'],
      gdpr: ['Article 30'],
      soc2: ['CC7.2']
    }
  };

  logger.warn(entry);

  // Audit-critical events go to long-term storage
  if (['AUTH_LOGIN_FAILURE', 'AUTHZ_ACCESS_DENIED', 'AUTHZ_PRIVILEGE_ESCALATION', 'DATA_DELETE', 'DATA_EXPORT'].includes(eventType)) {
    auditLogger.info(entry);
  }
}

// Request logging middleware
app.use((req, res, next) => {
  const startTime = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - startTime;
    logger.info({
      type: 'HTTP_REQUEST',
      method: req.method,
      url: req.originalUrl,
      statusCode: res.statusCode,
      duration: duration,
      ip: req.ip,
      userId: req.user?.id || 'anonymous'
    });
  });

  next();
});

// Authentication endpoint with comprehensive logging
app.post('/api/login', async (req, res) => {
  const { username } = req.body;

  try {
    // Authentication logic here...
    const authResult = await authenticate(username, req.body.password);

    if (authResult.success) {
      logSecurityEvent(SecurityEvents.AUTHENTICATION.LOGIN_SUCCESS, {
        username: username,
        method: 'password'
      }, req);
      res.json({ success: true, token: authResult.token });
    } else {
      logSecurityEvent(SecurityEvents.AUTHENTICATION.LOGIN_FAILURE, {
        username: username,
        reason: authResult.reason,
        attemptCount: authResult.attemptCount
      }, req);
      res.status(401).json({ error: 'Invalid credentials' });
    }
  } catch (error) {
    logger.error({
      type: 'AUTH_ERROR',
      error: error.message,
      stack: process.env.NODE_ENV !== 'production' ? error.stack : undefined
    });
    res.status(500).json({ error: 'Authentication service unavailable' });
  }
});

// Health check for log shipping verification
app.get('/api/health/logging', async (req, res) => {
  try {
    // Verify Elasticsearch connectivity
    const esHealth = await esClient.cluster.health();

    // Verify local log write capability
    const testEntry = { test: true, timestamp: new Date().toISOString() };
    logger.info(testEntry);

    res.json({
      status: 'healthy',
      elasticsearch: esHealth.status,
      localLogging: 'operational',
      retentionConfig: config.retention
    });
  } catch (error) {
    res.status(503).json({
      status: 'unhealthy',
      error: error.message
    });
  }
});

app.listen(3000, () => {
  logger.info({ type: 'SERVER_START', port: 3000 });
});
```

**Elasticsearch ILM Policy for Compliance**:

```json
{
  "policy": {
    "phases": {
      "hot": {
        "actions": {
          "rollover": {
            "max_size": "50gb",
            "max_age": "30d"
          }
        }
      },
      "warm": {
        "min_age": "30d",
        "actions": {
          "shrink": { "number_of_shards": 1 },
          "forcemerge": { "max_num_segments": 1 }
        }
      },
      "cold": {
        "min_age": "90d",
        "actions": {
          "freeze": {}
        }
      },
      "delete": {
        "min_age": "2555d",
        "actions": {
          "delete": {}
        }
      }
    }
  }
}
```

**Defense in Depth Layers**:

1. **Local retention with rotation**: Logs preserved locally even if network fails
```javascript
// Local logs survive network outages
const localTransport = new DailyRotateFile({
  filename: '/var/log/app/security-%DATE%.log',
  maxFiles: '365d'
});
```

2. **Centralized immutable storage**: Attackers cannot delete logs from compromised server
```javascript
// Elasticsearch with write-only API keys
const esClient = new Client({
  auth: { apiKey: process.env.ES_WRITE_ONLY_KEY }  // No delete permissions
});
```

3. **Chain hashing for tamper detection**: Any modification breaks the hash chain
```javascript
function verifyLogIntegrity(logs) {
  let previousHash = 'GENESIS';
  for (const log of logs) {
    const expectedHash = crypto.createHash('sha256')
      .update(JSON.stringify({...log, chainHash: undefined}) + previousHash)
      .digest('hex');
    if (log.chainHash !== expectedHash) {
      return { valid: false, tamperedAt: log.timestamp };
    }
    previousHash = log.chainHash;
  }
  return { valid: true };
}
```

**Additional Protections**:
- **Write-once storage**: Configure Elasticsearch indices as append-only
- **Log shipping monitoring**: Alert if logs stop flowing to central server
- **Geographic redundancy**: Replicate logs to separate data centers
- **Encryption at rest**: All log storage encrypted with KMS-managed keys
- **Access controls**: Separate permissions for log writing vs. reading
- **Retention automation**: ILM policies enforce compliance automatically

Log rotation is essential, but be careful not to delete logs too quickly. The SolarWinds attack succeeded partly because attackers knew most organizations only kept logs for 30-90 days, allowing them to remain undetected while evidence was automatically deleted.

**VULNERABLE CODE**:

```java
import java.util.logging.*;
import java.io.IOException;

public class InsecureLoggingConfig {
    private static final Logger logger = Logger.getLogger(InsecureLoggingConfig.class.getName());

    public static void configureLogging() {
        try {
            // VULNERABLE: Only keeps 3 days of logs with small file sizes
            // Security events will be lost before forensic analysis can occur
            FileHandler fileHandler = new FileHandler(
                "/var/log/app/application.log",
                1024 * 1024,  // 1MB per file
                3,            // Only 3 rotating files = ~3 days of logs
                false         // Don't append, overwrite
            );

            fileHandler.setFormatter(new SimpleFormatter());
            logger.addHandler(fileHandler);
            logger.setLevel(Level.INFO);

            // No retention policy for security-critical events
            // No separate handling for authentication/authorization logs
            // No archival strategy

        } catch (IOException e) {
            System.err.println("Failed to configure logging: " + e.getMessage());
        }
    }

    public static void logSecurityEvent(String event) {
        // All logs go to the same short-retention location
        logger.info("Security Event: " + event);
    }
}
```

**Attack Scenario**:
```text
Day 1: Attacker gains initial access via phishing
Day 5: Attacker establishes persistence mechanisms
Day 10: Logs from Day 1-3 automatically deleted
Day 30: Attacker begins data exfiltration
Day 45: Breach detected - but initial access logs are gone
Day 46: Forensic team cannot determine entry point or full scope
```

**Why This Is Dangerous**:
- Only 3 days of logs retained - APT attacks average 287 days dwell time
- Security events mixed with application logs - no prioritized retention
- No archival to immutable storage - attackers can delete evidence
- No compliance with regulations (PCI-DSS requires 1 year, HIPAA requires 6 years)

**SECURE VERSION**:

```java
import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.apache.logging.log4j.core.config.Configurator;
import org.apache.logging.log4j.core.config.builder.api.*;
import org.apache.logging.log4j.core.config.builder.impl.BuiltConfiguration;

public class SecureLoggingConfig {
    private static final Logger appLogger = LogManager.getLogger("application");
    private static final Logger securityLogger = LogManager.getLogger("security");
    private static final Logger auditLogger = LogManager.getLogger("audit");

    // Retention periods based on compliance requirements
    private static final String APP_LOG_RETENTION = "30d";      // 30 days for app logs
    private static final String SECURITY_LOG_RETENTION = "1y";   // 1 year for security
    private static final String AUDIT_LOG_RETENTION = "7y";      // 7 years for audit/compliance

    public static void configureSecureLogging() {
        ConfigurationBuilder<BuiltConfiguration> builder = 
            ConfigurationBuilderFactory.newConfigurationBuilder();

        // Application logs - 30 day retention with daily rotation
        LayoutComponentBuilder appLayout = builder.newLayout("PatternLayout")
            .addAttribute("pattern", "%d{ISO8601} [%t] %-5level %logger{36} - %msg%n");

        ComponentBuilder<?> appRollover = builder.newComponent("DefaultRolloverStrategy")
            .addAttribute("max", "30");  // Keep 30 daily files

        ComponentBuilder<?> appTrigger = builder.newComponent("Policies")
            .addComponent(builder.newComponent("TimeBasedTriggeringPolicy")
                .addAttribute("interval", "1"));

        AppenderComponentBuilder appAppender = builder.newAppender("AppFile", "RollingFile")
            .addAttribute("fileName", "/var/log/app/application.log")
            .addAttribute("filePattern", "/var/log/app/application-%d{yyyy-MM-dd}.log.gz")
            .add(appLayout)
            .addComponent(appTrigger)
            .addComponent(appRollover);

        // Security logs - 1 year retention with compression
        ComponentBuilder<?> secRollover = builder.newComponent("DefaultRolloverStrategy")
            .addAttribute("max", "365");  // Keep 365 daily files = 1 year

        AppenderComponentBuilder secAppender = builder.newAppender("SecurityFile", "RollingFile")
            .addAttribute("fileName", "/var/log/app/security/security.log")
            .addAttribute("filePattern", "/var/log/app/security/security-%d{yyyy-MM-dd}.log.gz")
            .add(appLayout)
            .addComponent(appTrigger)
            .addComponent(secRollover);

        // Audit logs - 7 year retention with archival
        ComponentBuilder<?> auditRollover = builder.newComponent("DefaultRolloverStrategy")
            .addAttribute("max", "2555");  // ~7 years of daily files

        AppenderComponentBuilder auditAppender = builder.newAppender("AuditFile", "RollingFile")
            .addAttribute("fileName", "/var/log/app/audit/audit.log")
            .addAttribute("filePattern", "/var/log/app/audit/audit-%d{yyyy-MM-dd}.log.gz")
            .add(appLayout)
            .addComponent(appTrigger)
            .addComponent(auditRollover);

        builder.add(appAppender);
        builder.add(secAppender);
        builder.add(auditAppender);

        // Configure loggers with appropriate appenders
        builder.add(builder.newLogger("application", org.apache.logging.log4j.Level.INFO)
            .add(builder.newAppenderRef("AppFile")));
        builder.add(builder.newLogger("security", org.apache.logging.log4j.Level.INFO)
            .add(builder.newAppenderRef("SecurityFile")));
        builder.add(builder.newLogger("audit", org.apache.logging.log4j.Level.INFO)
            .add(builder.newAppenderRef("AuditFile")));

        Configurator.initialize(builder.build());
    }

    public static void logSecurityEvent(String eventType, String details, String userId) {
        securityLogger.info("EVENT_TYPE={} USER={} DETAILS={}", eventType, userId, details);
    }

    public static void logAuditEvent(String action, String resource, String userId, boolean success) {
        auditLogger.info("ACTION={} RESOURCE={} USER={} SUCCESS={} TIMESTAMP={}", 
            action, resource, userId, success, System.currentTimeMillis());
    }
}
```

**Key Security Controls**:
- **Tiered retention**: Different retention periods based on log criticality (30 days, 1 year, 7 years)
- **Separate log streams**: Security and audit logs isolated from application logs
- **Compression**: Logs compressed to reduce storage costs while maintaining availability
- **Compliance alignment**: Retention periods meet PCI-DSS, HIPAA, SOX requirements

Excellent questions. Sophisticated attackers routinely delete or modify logs to cover their tracks. You need immutable log storage and efficient archival strategies.

**PRODUCTION PATTERN**:

```java
import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.apache.logging.log4j.ThreadContext;
import software.amazon.awssdk.services.cloudwatchlogs.CloudWatchLogsClient;
import software.amazon.awssdk.services.cloudwatchlogs.model.*;
import software.amazon.awssdk.services.s3.S3Client;
import software.amazon.awssdk.services.s3.model.*;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.*;

public class ImmutableLogManager {
    private static final Logger securityLogger = LogManager.getLogger("security");
    private static final Logger auditLogger = LogManager.getLogger("audit");

    private final CloudWatchLogsClient cloudWatchClient;
    private final S3Client s3Client;
    private final String logGroupName;
    private final String archiveBucket;
    private final String hmacKey;
    private final BlockingQueue<LogEntry> logQueue;
    private final ScheduledExecutorService archivalScheduler;

    // Hash chain for tamper detection
    private String previousLogHash = "GENESIS";
    private final Object hashLock = new Object();

    public ImmutableLogManager(String logGroupName, String archiveBucket, String hmacKey) {
        this.cloudWatchClient = CloudWatchLogsClient.create();
        this.s3Client = S3Client.create();
        this.logGroupName = logGroupName;
        this.archiveBucket = archiveBucket;
        this.hmacKey = hmacKey;
        this.logQueue = new LinkedBlockingQueue<>(10000);
        this.archivalScheduler = Executors.newScheduledThreadPool(2);

        initializeLogGroup();
        startAsyncProcessing();
        scheduleArchival();
    }

    private void initializeLogGroup() {
        try {
            // Create log group with 1-year retention
            cloudWatchClient.createLogGroup(CreateLogGroupRequest.builder()
                .logGroupName(logGroupName)
                .build());

            // Set retention policy - logs automatically kept for 1 year
            cloudWatchClient.putRetentionPolicy(PutRetentionPolicyRequest.builder()
                .logGroupName(logGroupName)
                .retentionInDays(365)  // 1 year retention in CloudWatch
                .build());

        } catch (ResourceAlreadyExistsException e) {
            // Log group already exists - OK
        }
    }

    public void logSecurityEvent(SecurityEvent event) {
        // Add correlation ID and timestamp
        String correlationId = ThreadContext.get("correlationId");
        if (correlationId == null) {
            correlationId = UUID.randomUUID().toString();
        }

        LogEntry entry = new LogEntry();
        entry.timestamp = Instant.now();
        entry.correlationId = correlationId;
        entry.eventType = event.getType();
        entry.severity = event.getSeverity();
        entry.userId = event.getUserId();
        entry.sourceIp = event.getSourceIp();
        entry.resource = event.getResource();
        entry.action = event.getAction();
        entry.outcome = event.getOutcome();
        entry.details = event.getDetails();

        // Generate hash chain for tamper detection
        synchronized (hashLock) {
            entry.previousHash = previousLogHash;
            entry.entryHash = computeHash(entry);
            entry.hmac = computeHMAC(entry);
            previousLogHash = entry.entryHash;
        }

        // Non-blocking queue for high throughput
        if (!logQueue.offer(entry)) {
            // Queue full - log synchronously as fallback
            sendToCloudWatch(Collections.singletonList(entry));
            securityLogger.warn("Log queue full - sent synchronously");
        }

        // Also log locally for immediate access
        securityLogger.info("SECURITY_EVENT: {}", entry.toJson());
    }

    private String computeHash(LogEntry entry) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            String data = entry.previousHash + entry.timestamp + entry.eventType + 
                         entry.userId + entry.details;
            byte[] hash = digest.digest(data.getBytes(StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Hash computation failed", e);
        }
    }

    private String computeHMAC(LogEntry entry) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            SecretKeySpec keySpec = new SecretKeySpec(
                hmacKey.getBytes(StandardCharsets.UTF_8), "HmacSHA256");
            mac.init(keySpec);
            byte[] hmacBytes = mac.doFinal(entry.toJson().getBytes(StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hmacBytes);
        } catch (Exception e) {
            throw new RuntimeException("HMAC computation failed", e);
        }
    }

    private void startAsyncProcessing() {
        Thread processor = new Thread(() -> {
            List<LogEntry> batch = new ArrayList<>();
            while (true) {
                try {
                    LogEntry entry = logQueue.poll(1, TimeUnit.SECONDS);
                    if (entry != null) {
                        batch.add(entry);
                    }

                    // Send batch when size reached or timeout
                    if (batch.size() >= 100 || (entry == null && !batch.isEmpty())) {
                        sendToCloudWatch(batch);
                        batch.clear();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        });
        processor.setDaemon(true);
        processor.setName("log-processor");
        processor.start();
    }

    private void sendToCloudWatch(List<LogEntry> entries) {
        try {
            List<InputLogEvent> events = new ArrayList<>();
            for (LogEntry entry : entries) {
                events.add(InputLogEvent.builder()
                    .timestamp(entry.timestamp.toEpochMilli())
                    .message(entry.toJson())
                    .build());
            }

            String streamName = "security-" + java.time.LocalDate.now();

            // Ensure stream exists
            try {
                cloudWatchClient.createLogStream(CreateLogStreamRequest.builder()
                    .logGroupName(logGroupName)
                    .logStreamName(streamName)
                    .build());
            } catch (ResourceAlreadyExistsException e) {
                // Stream exists - OK
            }

            cloudWatchClient.putLogEvents(PutLogEventsRequest.builder()
                .logGroupName(logGroupName)
                .logStreamName(streamName)
                .logEvents(events)
                .build());

        } catch (Exception e) {
            securityLogger.error("Failed to send logs to CloudWatch: {}", e.getMessage());
            // Write to local backup file as fallback
            writeToLocalBackup(entries);
        }
    }

    private void scheduleArchival() {
        // Archive to S3 Glacier for long-term retention (7+ years)
        archivalScheduler.scheduleAtFixedRate(() -> {
            try {
                archiveOldLogs();
            } catch (Exception e) {
                securityLogger.error("Archival failed: {}", e.getMessage());
            }
        }, 1, 24, TimeUnit.HOURS);  // Run daily
    }

    private void archiveOldLogs() {
        // Export logs older than 30 days to S3 Glacier
        java.time.LocalDate archiveDate = java.time.LocalDate.now().minusDays(30);
        String streamName = "security-" + archiveDate;

        try {
            // Get logs from CloudWatch
            GetLogEventsResponse response = cloudWatchClient.getLogEvents(
                GetLogEventsRequest.builder()
                    .logGroupName(logGroupName)
                    .logStreamName(streamName)
                    .startFromHead(true)
                    .build());

            if (!response.events().isEmpty()) {
                // Compress and upload to S3 with Glacier storage class
                StringBuilder logData = new StringBuilder();
                for (OutputLogEvent event : response.events()) {
                    logData.append(event.message()).append("\n");
                }

                String key = String.format("security-logs/%s/%s.log.gz", 
                    archiveDate.getYear(), archiveDate);

                s3Client.putObject(PutObjectRequest.builder()
                    .bucket(archiveBucket)
                    .key(key)
                    .storageClass(StorageClass.GLACIER_INSTANT_RETRIEVAL)
                    .objectLockMode(ObjectLockMode.GOVERNANCE)  // Prevent deletion
                    .objectLockRetainUntilDate(Instant.now().plusSeconds(86400 * 365 * 7))  // 7 years
                    .build(),
                    software.amazon.awssdk.core.sync.RequestBody.fromString(
                        compressData(logData.toString())));

                auditLogger.info("Archived logs for {} to S3 Glacier", archiveDate);
            }
        } catch (Exception e) {
            securityLogger.error("Failed to archive logs for {}: {}", archiveDate, e.getMessage());
        }
    }

    private String compressData(String data) {
        // In production, use GZIP compression
        // Simplified for example
        return data;
    }

    private void writeToLocalBackup(List<LogEntry> entries) {
        // Emergency fallback to local file
        for (LogEntry entry : entries) {
            securityLogger.info("BACKUP_LOG: {}", entry.toJson());
        }
    }

    // Verify log integrity
    public boolean verifyLogChain(List<LogEntry> entries) {
        String expectedPrevious = "GENESIS";
        for (LogEntry entry : entries) {
            // Verify hash chain
            if (!entry.previousHash.equals(expectedPrevious)) {
                securityLogger.error("Hash chain broken at entry: {}", entry.correlationId);
                return false;
            }

            // Verify HMAC
            String computedHmac = computeHMAC(entry);
            if (!computedHmac.equals(entry.hmac)) {
                securityLogger.error("HMAC verification failed for entry: {}", entry.correlationId);
                return false;
            }

            expectedPrevious = entry.entryHash;
        }
        return true;
    }

    public static class LogEntry {
        public Instant timestamp;
        public String correlationId;
        public String eventType;
        public String severity;
        public String userId;
        public String sourceIp;
        public String resource;
        public String action;
        public String outcome;
        public String details;
        public String previousHash;
        public String entryHash;
        public String hmac;

        public String toJson() {
            return String.format(
                "{\"timestamp\":\"%s\",\"correlationId\":\"%s\",\"eventType\":\"%s\"," +
                "\"severity\":\"%s\",\"userId\":\"%s\",\"sourceIp\":\"%s\"," +
                "\"resource\":\"%s\",\"action\":\"%s\",\"outcome\":\"%s\"," +
                "\"details\":\"%s\",\"prevHash\":\"%s\",\"hash\":\"%s\",\"hmac\":\"%s\"}",
                timestamp, correlationId, eventType, severity, userId, sourceIp,
                resource, action, outcome, details, previousHash, entryHash, hmac);
        }
    }

