    const entryString = JSON.stringify(logEntry);
    const combinedData = this.previousHash + entryString;
    const currentHash = crypto
      .createHash('sha256')
      .update(combinedData)
      .digest('hex');

    this.previousHash = currentHash;
    return currentHash;
  }

