  async archiveToS3(logPath, type, policy) {
    const fileContent = await fs.promises.readFile(logPath);
    const fileName = path.basename(logPath);

    const params = {
      Bucket: process.env.LOG_ARCHIVE_BUCKET,
      Key: `logs/${type}/${new Date().getFullYear()}/${fileName}`,
      Body: fileContent,
      ContentType: 'application/gzip',
      ServerSideEncryption: 'aws:kms',
      SSEKMSKeyId: process.env.LOG_ENCRYPTION_KEY,
      Metadata: {
