        'archive-date': new Date().toISOString()
      }
    };

    // Enable Object Lock for immutable logs
    if (policy.immutable) {
      params.ObjectLockMode = 'COMPLIANCE';
      params.ObjectLockRetainUntilDate = new Date(
        Date.now() + policy.archiveDays * 24 * 60 * 60 * 1000
      ).toISOString();
    }

    await this.s3Client.send(new PutObjectCommand(params));
    console.log(`Archived ${fileName} to S3 with ${policy.archiveDays}d retention`);
