  async verifyLogIntegrity(logFilePath) {
    const logs = await this.parseLogFile(logFilePath);
    let previousHash = null;
    let tamperedEntries = [];

    for (const entry of logs) {
      if (previousHash !== null) {
        const expectedHash = crypto
          .createHash('sha256')
          .update(previousHash + JSON.stringify(entry))
          .digest('hex');

        if (entry.integrityHash !== expectedHash) {
          tamperedEntries.push({
            eventId: entry.eventId,
            timestamp: entry.timestamp,
            reason: 'Hash chain broken'
          });
        }
      }
      previousHash = entry.integrityHash;
    }

    return {
      verified: tamperedEntries.length === 0,
      totalEntries: logs.length,
      tamperedEntries
    };
