        // Security event log appender with extended retention
        RollingFileAppender securityAppender = new RollingFileAppender();
        securityAppender.setContext(context);
        securityAppender.setFile("logs/security/security-audit.log");

        SizeAndTimeBasedRollingPolicy securityPolicy = new SizeAndTimeBasedRollingPolicy();
        securityPolicy.setContext(context);
        securityPolicy.setParent(securityAppender);
        securityPolicy.setFileNamePattern("logs/security/security-audit.%d{yyyy-MM-dd}.%i.log.gz");
        // SECURE: 1 year retention for security logs
        securityPolicy.setMaxHistory(SECURITY_LOG_RETENTION_DAYS);
        securityPolicy.setMaxFileSize(FileSize.valueOf("100MB"));
        securityPolicy.setTotalSizeCap(FileSize.valueOf("50GB"));
        securityPolicy.start();

        PatternLayoutEncoder securityEncoder = new PatternLayoutEncoder();
        securityEncoder.setContext(context);
        // SECURE: Comprehensive security log format with all required fields
        securityEncoder.setPattern(
            "%d{ISO8601} | %X{correlationId} | %X{userId} | %X{sessionId} | " +
            "%X{sourceIp} | %X{userAgent} | %X{action} | %X{resource} | " +
            "%X{outcome} | %level | %logger | %msg%n"
        );
        securityEncoder.start();

        securityAppender.setRollingPolicy(securityPolicy);
        securityAppender.setEncoder(securityEncoder);
        securityAppender.start();
    }

