        MDC.put("userId", event.getUserId());
        MDC.put("sessionId", event.getSessionId());
        MDC.put("sourceIp", event.getSourceIp());
        MDC.put("userAgent", event.getUserAgent());
        MDC.put("action", event.getAction());
        MDC.put("resource", event.getResource());
        MDC.put("outcome", event.getOutcome());

        try {
            securityLogger.info(event.getMessage());
        } finally {
            MDC.clear();
        }
    }
}
