        this.primaryBucket = config.getPrimaryBucket();
        this.archiveBucket = config.getArchiveBucket();
        this.hmacKey = config.getHmacKey();
        this.scheduler = Executors.newScheduledThreadPool(4);
        this.uploadQueue = new LinkedBlockingQueue<>(10000);

        initializeLifecyclePolicies();
        startBackgroundWorkers();
    }

