        logger.info("SECURITY_STANDARD: 1 year, transition to Glacier after 90 days");
        logger.info("AUDIT: 6 years, transition to Glacier after 30 days");
        logger.info("OPERATIONAL: 90 days in S3 Standard");
    }

    private void startBackgroundWorkers() {
        // Batch upload worker
        scheduler.scheduleAtFixedRate(this::processBatchUploads, 0, 1, TimeUnit.MINUTES);

        // Integrity verification worker
        scheduler.scheduleAtFixedRate(this::verifyLogIntegrity, 0, 1, TimeUnit.HOURS);

        // Retention enforcement worker
        scheduler.scheduleAtFixedRate(this::enforceRetentionPolicies, 0, 24, TimeUnit.HOURS);
    }

    /**
     * Archive logs with tamper-evident sealing
     */
    public LogArchiveResult archiveLogs(List<LogEntry> entries, RetentionTier tier) {
        String batchId = UUID.randomUUID().toString();
        Instant archiveTime = Instant.now();

        try {
            // Step 1: Serialize and compress logs
            byte[] compressedData = compressLogEntries(entries);

            // Step 2: Calculate integrity hash
            String sha256Hash = calculateSHA256(compressedData);

            // Step 3: Generate HMAC for tamper detection
            String hmacSignature = generateHMAC(compressedData);

            // Step 4: Create tamper-evident metadata
            LogArchiveMetadata metadata = new LogArchiveMetadata();
            metadata.setBatchId(batchId);
            metadata.setArchiveTime(archiveTime);
            metadata.setEntryCount(entries.size());
            metadata.setRetentionTier(tier);
            metadata.setSha256Hash(sha256Hash);
            metadata.setHmacSignature(hmacSignature);
            metadata.setExpirationDate(archiveTime.plus(tier.getRetentionPeriod()));
            metadata.setSourceHost(getHostname());
            metadata.setFirstEventTime(entries.get(0).getTimestamp());
            metadata.setLastEventTime(entries.get(entries.size() - 1).getTimestamp());

            // Step 5: Upload to S3 with appropriate storage class
            String objectKey = buildObjectKey(tier, archiveTime, batchId);
            uploadToS3(objectKey, compressedData, metadata, tier);

            // Step 6: Replicate to secondary region (disaster recovery)
            replicateToSecondaryRegion(objectKey, compressedData, metadata);

            // Step 7: Record in integrity ledger
            recordInIntegrityLedger(metadata);

            logger.info("Archived {} log entries to {} with retention {}", 
                entries.size(), objectKey, tier);

            return new LogArchiveResult(batchId, objectKey, sha256Hash, true);

        } catch (Exception e) {
            logger.error("Failed to archive log batch {}: {}", batchId, e.getMessage());
            // Queue for retry
            queueForRetry(entries, tier);
            return new LogArchiveResult(batchId, null, null, false);
        }
    }

    private void uploadToS3(String key, byte[] data, LogArchiveMetadata metadata, 
                           RetentionTier tier) {
        ObjectMetadata s3Metadata = new ObjectMetadata();
        s3Metadata.setContentLength(data.length);
        s3Metadata.setContentType("application/gzip");
        s3Metadata.addUserMetadata("x-log-batch-id", metadata.getBatchId());
        s3Metadata.addUserMetadata("x-log-sha256", metadata.getSha256Hash());
        s3Metadata.addUserMetadata("x-log-hmac", metadata.getHmacSignature());
        s3Metadata.addUserMetadata("x-log-entry-count", 
            String.valueOf(metadata.getEntryCount()));
        s3Metadata.addUserMetadata("x-log-retention-tier", tier.name());
        s3Metadata.addUserMetadata("x-log-expiration", 
            metadata.getExpirationDate().toString());

        PutObjectRequest request = new PutObjectRequest(
            primaryBucket, key, new ByteArrayInputStream(data), s3Metadata
        );

        // Set storage class based on retention tier
        switch (tier) {
            case SECURITY_CRITICAL:
            case AUDIT:
                request.setStorageClass(StorageClass.GlacierDeepArchive);
                break;
            case SECURITY_STANDARD:
                request.setStorageClass(StorageClass.StandardInfrequentAccess);
                break;
            default:
                request.setStorageClass(StorageClass.Standard);
        }

        // Enable Object Lock for immutability (WORM compliance)
        if (tier == RetentionTier.SECURITY_CRITICAL || tier == RetentionTier.AUDIT) {
            s3Metadata.addUserMetadata("x-amz-object-lock-mode", "COMPLIANCE");
            s3Metadata.addUserMetadata("x-amz-object-lock-retain-until-date", 
                metadata.getExpirationDate().toString());
        }

        s3Client.putObject(request);
    }

    /**
     * Verify integrity of archived logs
     */
    public IntegrityVerificationResult verifyArchiveIntegrity(String batchId) {
        try {
            LogArchiveMetadata storedMetadata = getMetadataFromLedger(batchId);
            byte[] archivedData = downloadFromS3(storedMetadata.getObjectKey());

            // Verify SHA-256 hash
            String currentHash = calculateSHA256(archivedData);
            boolean hashValid = currentHash.equals(storedMetadata.getSha256Hash());

            // Verify HMAC signature
            String currentHmac = generateHMAC(archivedData);
            boolean hmacValid = currentHmac.equals(storedMetadata.getHmacSignature());

            if (!hashValid || !hmacValid) {
                // CRITICAL: Log tampering detected
                alertSecurityTeam("LOG_TAMPERING_DETECTED", batchId, storedMetadata);
                logger.error("SECURITY ALERT: Log tampering detected for batch {}", batchId);
            }

            return new IntegrityVerificationResult(batchId, hashValid, hmacValid);

        } catch (Exception e) {
            logger.error("Integrity verification failed for batch {}: {}", batchId, e.getMessage());
            return new IntegrityVerificationResult(batchId, false, false);
        }
    }

    private byte[] compressLogEntries(List<LogEntry> entries) throws IOException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        try (GZIPOutputStream gzip = new GZIPOutputStream(baos)) {
            for (LogEntry entry : entries) {
                gzip.write(entry.toJson().getBytes(StandardCharsets.UTF_8));
                gzip.write('\n');
            }
        }
        return baos.toByteArray();
    }

    private String calculateSHA256(byte[] data) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(data);
        return Base64.getEncoder().encodeToString(hash);
    }

    private String generateHMAC(byte[] data) throws Exception {
        Mac mac = Mac.getInstance("HmacSHA256");
        SecretKeySpec keySpec = new SecretKeySpec(hmacKey, "HmacSHA256");
        mac.init(keySpec);
        byte[] hmac = mac.doFinal(data);
        return Base64.getEncoder().encodeToString(hmac);
    }

    private String buildObjectKey(RetentionTier tier, Instant time, String batchId) {
        return String.format("logs/%s/%tY/%tm/%td/%s.log.gz",
            tier.name().toLowerCase(), 
            Date.from(time), Date.from(time), Date.from(time), 
            batchId);
    }

