// TamperProofLogger adds cryptographic integrity verification
type TamperProofLogger struct {
	logger      *zap.Logger
	hmacKey     []byte
	chainHash   string
	chainMu     sync.Mutex
	remoteShip  chan LogEntry
}

type LogEntry struct {
	Timestamp     time.Time              `json:"timestamp"`
	Category      LogCategory            `json:"category"`
	EventType     string                 `json:"event_type"`
	Data          map[string]interface{} `json:"data"`
	PreviousHash  string                 `json:"previous_hash"`
	IntegrityHash string                 `json:"integrity_hash"`
}

func NewTamperProofLogger(category LogCategory) (*TamperProofLogger, error) {
	policy := retentionPolicies[category]

	logPath := fmt.Sprintf("/var/log/app/%s.log", category)

	logWriter := &lumberjack.Logger{
		Filename:   logPath,
		MaxSize:    policy.MaxSizeMB,
		MaxBackups: policy.MaxBackups,
		MaxAge:     policy.RetentionDays,
		Compress:   policy.Compress,
		LocalTime:  false,
	}

	encoderConfig := zapcore.EncoderConfig{
		TimeKey:        "timestamp",
		LevelKey:       "level",
		NameKey:        "logger",
		CallerKey:      "caller",
		MessageKey:     "message",
		StacktraceKey:  "stacktrace",
		LineEnding:     zapcore.DefaultLineEnding,
		EncodeLevel:    zapcore.LowercaseLevelEncoder,
		EncodeTime:     zapcore.ISO8601TimeEncoder,
		EncodeDuration: zapcore.SecondsDurationEncoder,
		EncodeCaller:   zapcore.ShortCallerEncoder,
	}

	core := zapcore.NewCore(
		zapcore.NewJSONEncoder(encoderConfig),
		zapcore.AddSync(logWriter),
		zap.InfoLevel,
	)

	zapLogger := zap.New(core, zap.AddCaller())

	// Load HMAC key from secure storage (HSM, Vault, etc.)
	hmacKey := loadHMACKeyFromSecureStorage()

	tpl := &TamperProofLogger{
		logger:     zapLogger,
		hmacKey:    hmacKey,
		chainHash:  "genesis",
		remoteShip: make(chan LogEntry, 10000),
	}

	// Start background goroutine to ship logs to immutable storage
	if policy.RemoteShip {
		go tpl.shipToImmutableStorage()
	}

	return tpl, nil
}

func (tpl *TamperProofLogger) LogSecurityEvent(eventType string, data map[string]interface{}) {
	tpl.chainMu.Lock()
	defer tpl.chainMu.Unlock()

	entry := LogEntry{
		Timestamp:    time.Now().UTC(),
		Category:     LogCategorySecurity,
		EventType:    eventType,
		Data:         data,
		PreviousHash: tpl.chainHash,
	}

	// Create hash chain for tamper detection
	entryBytes, _ := json.Marshal(entry)
	h := hmac.New(sha256.New, tpl.hmacKey)
	h.Write(entryBytes)
	entry.IntegrityHash = hex.EncodeToString(h.Sum(nil))
	tpl.chainHash = entry.IntegrityHash

	// Convert to zap fields
	fields := []zap.Field{
		zap.String("event_type", eventType),
		zap.String("category", string(entry.Category)),
		zap.Time("event_timestamp", entry.Timestamp),
		zap.String("previous_hash", entry.PreviousHash),
		zap.String("integrity_hash", entry.IntegrityHash),
	}

	for k, v := range data {
		fields = append(fields, zap.Any(k, v))
	}

	tpl.logger.Info("security_event", fields...)

	// Queue for remote shipping to immutable storage
	select {
	case tpl.remoteShip <- entry:
	default:
		// Buffer full - this is a critical alert condition
		tpl.logger.Error("log_shipping_buffer_full",
			zap.String("alert", "CRITICAL"),
			zap.String("action_required", "increase buffer or check remote storage"),
		)
	}
}

func (tpl *TamperProofLogger) shipToImmutableStorage() {
	for entry := range tpl.remoteShip {
		// Ship to immutable storage (S3 with Object Lock, Azure Immutable Blob, etc.)
		err := shipToS3WithObjectLock(entry)
		if err != nil {
			// Critical: local backup and alert
			tpl.logger.Error("failed_to_ship_log",
				zap.Error(err),
				zap.String("entry_hash", entry.IntegrityHash),
			)
			// Write to local backup queue
			writeToLocalBackupQueue(entry)
		}
	}
}

