const { createLogger, format, transports } = winston;

// DANGEROUS: Minimal logging with no retention strategy
const logger = createLogger({
  level: 'info',
  format: format.simple(),
  transports: [
    // Only logs to console - lost on restart
    new transports.Console(),
    // File with tiny max size and no archive
    new transports.File({
      filename: 'app.log',
      maxsize: 1048576, // 1MB - easily overwritten
      maxFiles: 1       // Only keeps 1 file
    })
  ]
});

// Logs critical security events but they're quickly lost
function logSecurityEvent(event) {
  logger.info(`Security event: ${event.type}`);
}

// Authentication attempts logged but not retained
