**Key Security Controls**:
- **Daily rotation with compression**: Logs are rotated daily and compressed to save space while maintaining history
- **1-year retention for security logs**: Meets most compliance requirements (PCI-DSS requires 1 year, some require 7 years)
- **Structured JSON format**: Enables efficient searching and analysis in SIEM systems
- **Audit trail**: The audit file tracks log file creation/deletion for integrity verification

For distributed systems, you need centralized log aggregation with immutable storage and tiered retention policies. Local logs can be lost when containers crash or are replaced, so logs must be shipped to a central location in near real-time.

**PRODUCTION PATTERN**:

```javascript
const winston = require('winston');
const DailyRotateFile = require('winston-daily-rotate-file');
const { ElasticsearchTransport } = require('winston-elasticsearch');
const { S3StreamLogger } = require('s3-streamlogger');
const crypto = require('crypto');

// Configuration based on environment and compliance requirements
const LOG_CONFIG = {
  retention: {
    security: parseInt(process.env.SECURITY_LOG_RETENTION_DAYS) || 365,
    audit: parseInt(process.env.AUDIT_LOG_RETENTION_DAYS) || 2555, // 7 years
    application: parseInt(process.env.APP_LOG_RETENTION_DAYS) || 90,
    debug: parseInt(process.env.DEBUG_LOG_RETENTION_DAYS) || 7
  },
  elasticsearch: {
    node: process.env.ELASTICSEARCH_URL,
    auth: {
      username: process.env.ES_USERNAME,
      password: process.env.ES_PASSWORD
    }
  },
  s3: {
    bucket: process.env.LOG_ARCHIVE_BUCKET,
    region: process.env.AWS_REGION || 'us-east-1'
  }
};

// S3 transport for long-term immutable storage
const s3Stream = new S3StreamLogger({
  bucket: LOG_CONFIG.s3.bucket,
  folder: `logs/${process.env.SERVICE_NAME}`,
  name_format: '%Y-%m-%d-%H-%M-security.log',
  rotate_every: 3600000, // Rotate hourly
  max_file_size: 52428800, // 50MB
  upload_every: 10000,   // Upload buffer every 10 seconds
  buffer_size: 1048576   // 1MB buffer
});

// Elasticsearch for searchable, centralized logs
const esTransport = new ElasticsearchTransport({
  level: 'info',
  clientOpts: LOG_CONFIG.elasticsearch,
  indexPrefix: 'app-logs',
  indexSuffixPattern: 'YYYY.MM.DD',
  transformer: (logData) => {
    return {
      '@timestamp': logData.timestamp,
      message: logData.message,
      severity: logData.level,
      ...logData.meta
    };
  }
});

// Local rotating file as fallback
const localSecurityTransport = new DailyRotateFile({
  filename: '/var/log/app/security-%DATE%.log',
  datePattern: 'YYYY-MM-DD-HH',
  zippedArchive: true,
  maxSize: '100m',
  maxFiles: `${LOG_CONFIG.retention.security}d`,
  createSymlink: true,
  symlinkName: 'security-current.log'
});

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
    winston.format.errors({ stack: true }),
    addLogIntegrity(),
    winston.format.json()
  ),
  defaultMeta: {
    service: process.env.SERVICE_NAME,
    instance: process.env.HOSTNAME,
    version: process.env.APP_VERSION,
    environment: process.env.NODE_ENV
  },
  transports: [
    localSecurityTransport,
    esTransport,
    new winston.transports.Stream({ stream: s3Stream })
  ],
  exitOnError: false
});

// Custom format to add log integrity hash
function addLogIntegrity() {
  return winston.format((info) => {
    const logContent = JSON.stringify({
      timestamp: info.timestamp,
      level: info.level,
      message: info.message,
      ...info
    });
    info.integrity = crypto
      .createHmac('sha256', process.env.LOG_HMAC_SECRET)
      .update(logContent)
      .digest('hex');
    return info;
  })();
}

// Comprehensive security event logger
class SecurityLogger {
  constructor(baseLogger) {
    this.logger = baseLogger;
    this.correlationStore = new Map();
  }

  logAuthEvent(event) {
    this.logger.warn({
      category: 'AUTHENTICATION',
      eventId: crypto.randomUUID(),
      eventType: event.type,
      userId: event.userId,
      username: this.maskPII(event.username),
      sourceIp: event.sourceIp,
      userAgent: event.userAgent,
      geoLocation: event.geoLocation,
      outcome: event.outcome,
      failureReason: event.failureReason,
      mfaUsed: event.mfaUsed,
      sessionId: event.sessionId,
      correlationId: event.correlationId,
      retentionClass: 'SECURITY',
      retentionDays: LOG_CONFIG.retention.security
    });
  }

  logAccessEvent(event) {
    this.logger.info({
      category: 'ACCESS',
      eventId: crypto.randomUUID(),
      eventType: event.type,
      userId: event.userId,
      resource: event.resource,
      action: event.action,
      outcome: event.outcome,
      dataClassification: event.dataClassification,
      recordsAccessed: event.recordCount,
      correlationId: event.correlationId,
      retentionClass: 'AUDIT',
      retentionDays: LOG_CONFIG.retention.audit
    });
  }

  logDataExfiltrationAlert(event) {
    this.logger.error({
      category: 'DATA_EXFILTRATION',
      priority: 'CRITICAL',
      eventId: crypto.randomUUID(),
      userId: event.userId,
      sourceIp: event.sourceIp,
      dataVolume: event.dataVolume,
      timeWindow: event.timeWindow,
      affectedRecords: event.affectedRecords,
      alertThreshold: event.threshold,
      correlationId: event.correlationId,
      retentionClass: 'SECURITY',
      retentionDays: LOG_CONFIG.retention.security,
      immutable: true
    });
  }

  maskPII(value) {
    if (!value) return null;
    if (value.includes('@')) {
      const [local, domain] = value.split('@');
      return `${local.substring(0, 2)}***@${domain}`;
    }
    return value.length > 4
      ? `${value.substring(0, 2)}***${value.slice(-2)}`
      : '***';
  }
}

// Log shipping health monitor
class LogShippingMonitor {
  constructor(logger) {
    this.logger = logger;
    this.metrics = {
      shipped: 0,
      failed: 0,
      lastShippedAt: null,
      backlogSize: 0
    };
  }

  recordSuccess() {
    this.metrics.shipped++;
    this.metrics.lastShippedAt = new Date();
  }

  recordFailure(error) {
    this.metrics.failed++;
    this.logger.error({
      category: 'LOG_SHIPPING',
      eventType: 'SHIPPING_FAILURE',
      error: error.message,
      backlogSize: this.metrics.backlogSize
    });
  }

  checkHealth() {
    const now = new Date();
    const timeSinceLastShip = now - this.metrics.lastShippedAt;
    if (timeSinceLastShip > 60000) { // 1 minute
      this.logger.error({
        category: 'LOG_SHIPPING',
        eventType: 'SHIPPING_DELAYED',
        delayMs: timeSinceLastShip,
        failedCount: this.metrics.failed
      });
    }
  }
}

const securityLogger = new SecurityLogger(logger);
const shippingMonitor = new LogShippingMonitor(logger);

// Monitor log transport health
